css:
/*作者：@kuku（小红书同名）  */

/*⚠️ 此css美化禁二传二改·禁商用倒卖*/


/*手机美化适配二改自@多云熊老师*/

/* === 字体=== */
@font-face {
  font-family: "MiaoMiao";  
  src: url("https://files.catbox.moe/ljqewe.otf") format("truetype");
  font-display: swap;       
}

body, button, input, textarea {
  font-family: "MiaoMiao", "Microsoft YaHei", sans-serif !important;
}




/*ui背景*/
.drawer-content {
    background-image: url('https://files.catbox.moe/0mp8du.jpeg');
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
}


/*想换壁纸删除这段*/
#sheld {
    background: linear-gradient(rgba(0, 0, 0, 0), rgba(0, 0, 0, 0)), 
                url('https://files.catbox.moe/5k1glf.jpeg') !important;
    background-size: cover !important;
    background-position: center !important;
    background-attachment: fixed !important;
    background-repeat: no-repeat !important;
}


/* 头像位置 */
div[is_user] .mesAvatarWrapper { 
    position: absolute;
    top: 1px !important; /* char头像上下位置🍉  */
    left: 7% !important;/* user和char头像的左右位置🍉 */
    transform: translateX(-50%);
    z-index: 0;
    margin: 0 !important;
}


div[is_user="true"] .mesAvatarWrapper {
    top: 1px !important; /* user头像的上下位置🍉 */
}


.avatar img {
    width: 40px !important;  
    height: 40px !important;
    min-width: unset !important;
    min-height: unset !important;
    box-shadow: none !important; 
    transition: all 0.3s ease; 
}

/* 头像尺寸调整 - 覆盖原有样式 */
.avatar img {
    width: 220px !important;  /* 宽🍉 */
    height: 220px !important; /* 高🍉 */
    object-fit: cover !important; 
    border-radius: 500% !important; 
    box-shadow: 0 4px 12px rgba(255,255,255,0.5) !important; 
}

.avatar img {
  -webkit-mask-image: url('https://files.catbox.moe/65f1by.png');
  mask-image: url('https://files.catbox.moe/65f1by.png');
  -webkit-mask-size: contain;
  mask-size: contain;
  -webkit-mask-repeat: no-repeat;
  mask-repeat: no-repeat;
  -webkit-mask-position: center;
  mask-position: center;
}

/* 禁止交互 */
.avatar, 
.avatar img,
.mesAvatarWrapper {
  pointer-events: none !important; 
  cursor: default !important; 
  user-select: none !important; 
}

#right-nav-panel .avatar,
#right-nav-panel .avatar img,
#character_popup .avatar {
  pointer-events: auto !important;  
  cursor: pointer !important;      
  user-select: auto !important;    
}


/* 调整对话框基础尺寸 */
.mes {
    --bubble-width: 90%;  
    --vertical-spacing: 3rem; 

    width: var(--bubble-width) !important;
    min-height: var(--bubble-min-height);
    margin: var(--vertical-spacing) auto !important; 
    padding: 1rem -0.2rem !important; 
    left: 1px;
}


.mes_text {
    padding: 200px 1px 20px 1px !important; /* 上 右 下 左 */
}

.mes_block {
    position: relative;
    z-index: 999 !important; 
    isolation: isolate; 
}




/* 气泡 */
.mes[is_user="true"] {
    background: linear-gradient(
        to bottom, 
        rgba(255, 255, 255, 1) 60%,  
        rgba(255, 255, 255, 1) 100%
    ) !important;
    border: px solid #ceb7c6 !important; 
    box-shadow: 0 0px 2px 1px rgba(87,87,87,0.4) !important;
    border-radius: 5px !important;
}

/* AI */
.mes[is_user="false"] {
    background: linear-gradient(
        to bottom,
        rgba(255, 255, 255, 1) 60%,  
        rgba(255, 255, 255, 1) 100%
    ) !important;
    border: 0px solid #ceb7c6 !important; 
    box-shadow: 0 0px 2px 1px rgba(87,87,87,0.4) !important;
    border-radius: 5px !important;
}

.mes_block {
    position: relative;
    z-index: 2;
}

/* 头像框*/
.avatar::after {
    content: "";
    position: absolute;
    top: -12px;
    left: -4px;
    width: calc(80% + 22.5px);
    height: calc(96% + 25px);
    background-image: url("https://files.catbox.moe/p6xr5.gif");
    background-size: contain;
    background-repeat: no-repeat;
    z-index: 5 !important;
    pointer-events: none;
}

.avatar img {
    position: relative !important;
    z-index: 0 !important;
}




.mes::after {
  content: "";
  position: absolute;
  bottom: -108px;
  right: -19px;
  width: 358px; 
  height:358px; 
  background-image: url('https://files.catbox.moe/6sowmn.png'); 
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center;
  z-index: 1; 
}

.mes::before {
  content: "";
  display: block;
  width: 358px;  /* 图片宽度 */
  height: 358px;  /* 图片高度 */
  background-image: url('https://files.catbox.moe/yoziob.png');
  background-size: contain;
  background-repeat: no-repeat;
  position: absolute;
  top: -52px;   
  left: 50%;
  transform: translateX(-50%);
  z-index: 1;
}

/* 心 */
.fa-circle-stop::before {
  content: "" !important; 
  display: inline-block;
  width: 1.5em !important;   
  height: 1.5em !important;
  background: url("https://files.catbox.moe/ulh34s.gif") center/contain no-repeat; 
  vertical-align: middle !important;
  animation: spin 2s linear infinite; 
  transition: 0.3s ease;
}

q {
  text-decoration: underline dotted rgba(0, 0, 0, 0.3);
  text-underline-offset: 4px;
  font-style: normal;
}

/* 消息ID */
.mesIDDisplay {
    position: absolute !important;
    top: 130px !important;
    left: 25px !important;
    display: inline-block !important;
    font-size: 0.7em !important;
    font-family: 'MyCustomFont';
    z-index: 888 !important;
    opacity: 1;
    color: #A84343;
}

/* 时间戳 */
.mes_timer {
    position: absolute !important;
    top: 145px !important;
    left: 25px !important;  
    font-size: 0.7em !important;
    font-family: 'MyCustomFont';
    display: flex !important;
    gap: 4px;
    z-index: 888 !important;
    opacity: 1;
    color: #A84343;
}

/* 词符数 */
.tokenCounterDisplay {
    position: absolute !important;
    top: 160px !important;
    left: 25px !important;  
    display: flex !important;
    font-size: 0.7em !important;
    font-family: 'MyCustomFont';
    z-index: 888 !important;
    opacity: 1;
    color: #A84343;
}

@font-face {
  font-family: 'MyCustomFont';
  src: url('https://files.catbox.moe/7cdqh4.ttf') format('woff2'),
       url('https://files.catbox.moe/7cdqh4.ttf') format('woff');
  font-weight: normal;
  font-style: normal;
  font-display: swap;
}

#chat .ch_name {
  position: relative;
  display: flex;
  color: #333 !important;
  padding: 1px 0; 
  top: 200px !important;
  left: 0px !important;
  width: 100%; /* 用户名宽度 */
  max-width: 2800px; /* 最大宽度限制 */
}


#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt {
  --border-thickness: 2px; /* 边框高度控制变量 */
  --border-radius: 5px; 

  background-color: #fff !important;
  position: relative;
  border-radius: var(--border-radius) !important;
  overflow: visible !important; 
  z-index: 1;
  box-shadow: 
    inset 0 0 0 var(--border-thickness) #fff,
    inset 0 0 0 calc(var(--border-thickness) + 1px) #575757,

    0 1px 1px rgba(168, 67, 67, 0.1);
  transition: all 0.3s ease;
  font: calc(var(--mainFontSize) * 0.9) "MiaoMiao", sans-serif !important;
}

#completion_prompt_manager .completion_prompt_manager_footer {
    padding: 0px;
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt:not(.completion_prompt_manager_prompt_disabled) {
  opacity: 1;
  transition: opacity 0.3s ease;
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt_disabled {
  opacity: 0.3;
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt span span span,
#completion_prompt_manager .completion_prompt_manager_header_advanced span {
    filter: drop-shadow(0px 0px 2px var(--SmartThemeChatTintColor));
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name, #completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
    color: var(--customThemeColor-purple);
}



/* 悬停时提高透明度 */
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt:hover {
    opacity: 0.9;
}

.text_pole:not(.objective-task) {
  background-color: var(--ui-color-sec);
  border: none;
}

blockquote,
.quote-style,
[class*="quote"] {
    background-color: transparent !important;
    border: none !important;
    box-shadow: none !important;
    padding: 0 !important;
    margin: 0.8em 0 !important;
}

blockquote::before,
blockquote::after {
    content: "" !important;
}

/* 添加在全局样式中 */
#top-bar {

   z-index: 1000; 
}

#top-bar::after {
    content: "";
    position: fixed;
    top: var(--topBar-height, -15px); 
    left: 0px;
    width: 100%;
    height: 70px;
    background: url('https://files.catbox.moe/zbags4.png') center/cover no-repeat;
    z-index: 999; 
    pointer-events: none;
    filter: opacity(0.) drop-shadow(0 2px 4px rgba(0,0,0,0.0));
}

#main-content {
    margin-top: 150px; 
}

/* 滑块图案 */
input[type="range"]::-webkit-slider-thumb {
    width: 60px;
    height: 45px; 
    background: url('https://files.catbox.moe/wcgu1b.png') no-repeat center center; 
    background-size: contain; 
    border: none;
    border-radius: 0; 
    box-shadow: none;
    transition: width 0.2s, height 0.2s;
    z-index: 2;
}

input[type="range"] {
    background: #575757 !important;
    box-shadow: 0 1px 2px rgba(165,79,79,0.5) !important; 
    border: 1px solid #FFFFFF !important;
    height: 4px; 
}

.avatar,
.avatar::before,
.avatar::after {
    z-index: auto !important; 
}

/* 代码块 */
code, .hljs {
  position: relative;
  background: linear-gradient(
    20deg,
    rgba(255,255,255,0.8) 10%,
    rgba(255,255,255,0.8) 40%
  ) !important;
  border-radius: 2px !important;
  border: 1.5px solid #fff !important;
  box-shadow: 
    1px 2px 2px rgba(0,0,0,0.2), 
    inset 0px -1px 1px rgba(0,0,0,0.0), 
    inset 1px 1px 1px rgba(136,169,197,0.1); 
  border: px solid rgba(200,20,2,0.5) !important;
  transition: all 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
   color: #A56C6C;
   font: 
        calc(var(--mainFontSize) * 0.9) 
        "MiaoMiao", 
}

/* ===== 外部装饰图标 ===== */
pre {
  position: relative; 
  margin-bottom: 2em !important; 
  overflow: visible !important; 
  font: 
        calc(var(--mainFontSize) * 0.9) 
        "MiaoMiao", 
}
}

pre::after {
  content: "";
  position: absolute;
  bottom: -12px;  
  right: -5px;
  width: 40px;    
  height: 40px;
  background-image: url("https://files.catbox.moe/mg8j7.gif");
  background-size: contain;

  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  z-index: 1; 
}


/* 下拉框 */
select {
   background-size: 100%;
  overflow: visible !important;
  background-image: url("https://files.catbox.moe/6ce284.png");
  border: px dashed #ECE9F4 !important;
  background-position: center;
  box-shadow: 
    inset 0 0 0 1px #fff,
    0 2px 2px rgba(0, 0, 0, 0.08),
    inset 0 0 8px rgba(243, 246, 255, 1) !important;
  border-radius: 5px;
  transition: all 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
  position: relative;
  overflow: hidden;
  padding: 1px px !important;
  color: #fff;
   font: 
        calc(var(--mainFontSize) * 0.9) 
        "MiaoMiao", 
}

select, 
select option {
  color: #fff !important;
}

select option:checked {
  color: #fff !important;
  background-color: var(--text-color-main) !important;
  font: 
        calc(var(--mainFontSize) * 0.9) 
        "MiaoMiao", 
}

select option {
    text-align: center !important;
    text-align-last: center !important; 
}

/* 自定义勾选框配色 */
input[type="checkbox"] {
    --checkbox-bg: #fff;  
    --checkbox-accent: #575757; 

    background-color: var(--checkbox-bg) !important;
    box-shadow: 0 0 0 px var(--checkbox-accent) !important;
    transition: all 0.2s ease;
    border-radius: 15px !important;
}

/* 选中状态 */
input[type="checkbox"]:checked {
    background-color: var(--checkbox-accent) !important;
    box-shadow: 0 0 0 1px var(--checkbox-bg) !important;
}

/* 标题样式 */
.inline-drawer-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader {
  background-size: 100%;
  overflow: visible !important;
  background-image: url("https://files.catbox.moe/5lr8lq.png");
  border: px dashed #ECE9F4 !important;
  box-shadow: 
    inset 0 0 0 1px #fff,
    0 2px 2px rgba(0, 0, 0, 0.08),
    inset 0 0 8px rgba(243, 246, 255, 1) !important;
  border-radius: 5px;
  transition: all 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
  position: relative;
  overflow: hidden;
  padding: 5px 26px !important;
  color: #fff;
}


/* 极简滚动条 */
::-webkit-scrollbar {
    width: 4px !important; 
    height: 5px !important; 
}

::-webkit-scrollbar-track {
    background: transparent !important; /* 完全透明轨道 */
}

::-webkit-scrollbar-thumb {
    background: linear-gradient(to bottom, 
        #A54F4F 0%, 
        #A54F4F 5%, 
        #A54F4F 51%, 
        #575757 100%) !important;
    border-radius: 2px !important;
    border: none !important;
    transition: all 0.3s ease !important;
}

/* 输入框 */
input[type="text"],
input[type="number"],
input[type="switch"],
input:not([type]),
textarea:not([type="search"]) {
    background-color: #FFFFFF !important; 
    border-radius: 1px !important;
    border: 1px solid #A54F4F !important;
}

/* 上移输入框容器 */
#form_sheld {
  margin: 0 auto -10px auto !important; 
  transform: translateY(-20px); 
}

/* 调整输入框内边距 */
#send_form {
  padding: 0px 1px !important; 
  border-radius: 1px !important;
  width: 93.3% !important; 
    max-width: 1200px;
    min-height: 1px !important;
    box-shadow: 
    0 0 0 2px #333,    
    0 0 0 4px #FFFFFF,    
    0 0 0 5px #A54F4F;
}

#form_sheld::before {
    content: "";
    position: absolute;
    top: -72px; 
    left: 80%;
    transform: translateX(-50%);
    width: 105px; 
    height: 105px; 
    background-image: url("https://files.catboxmo/1tlllc.png"); 
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    z-index: 1; 
    pointer-events: none; 
    transition: all 0.3s ease; 
}

#send_form textarea {
  border: none !important;
  box-shadow: none !important;
}

#send_form textarea:focus {
  outline: none !important;
  border: none !important;
}

/* 思维链 */
.mes_reasoning_header {
    background: #fff !important;
    border: 1.5px solid #575757 !important;
    border-radius: 2px !important;
    box-shadow: 0 2px 4px rgba(196,183,209,0.3) !important;
    color: #333 !important;
    font-weight: 500;
    padding: 1px 15px !important;
    left: -1% !important;
    top: 200px !important;
}


/* 角色管理头像 */
#right-nav-panel .character_select .avatar {
    --avatar-base-size: 50px !important; 
    width: var(--avatar-base-size) !important;
    height: var(--avatar-base-size) !important;
    transform: scale(1) !important; 
    margin: -2px auto !important; 
    border: px solid #CAD1D9;
}


#right-nav-panel .character_select .avatar img {
    width: 100% !important;
    height: 100% !important;
    object-fit: cover;
    border-radius: 50px !important;
    box-shadow: 0 4px 5px rgba(213,213,213,0.9) !important;
}

/* 禁用收藏标记 */
#right-nav-panel .character_select.is_fav .avatar,
#persona-management-button .character_select.is_fav .avatar {
    outline: none !important;
    box-shadow: none !important;
}

#right-nav-panel .character_select.is_fav .ch_name,
#persona-management-button .character_select.is_fav .ch_name {
    color: inherit !important;
}


/* 移除特定界面头像装饰 */
#character_popup .avatar::before, 
#character_popup .avatar::after,
#user-settings-block .avatar::before, 
#user-settings-block .avatar::after,
#right-nav-panel .avatar::before, 
#right-nav-panel .avatar::after {
    display: none !important;
    background-image: none !important;
    animation: none !important;
}

/* 删掉 */
#persona-management-button .avatar::before,
#persona-management-button .avatar::after {
    content: none !important;
    display: none !important;
}

#persona-management-button .avatar img {
  width: 60px !important;  
  height: 60px !important; 
  min-width: unset !important;
  min-height: unset !important;
  top: -20px;
  left: -10px;
}

::-webkit-scrollbar-thumb:vertical {
    background-color: #FFEDF5;
    box-shadow: none;    
}

/* neo-range-input 背景美化 */
.neo-range-input {
    position: relative;
    background: linear-gradient(
            to right,
            rgba(255,255,255,0.2) 0%,
            rgba(255,255,255,0.1) 100%
        ),

    background-blend-mode: soft-light, multiply;
    box-shadow: inset 0 2px 8px rgba(0,0,0,0.03) !important;
}

@keyframes messageAppear {
  0% {
    opacity: 0;
    transform: translateY(40px) scale(0.95);
  }
  100% {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.mes {
  animation: messageAppear 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards;
  opacity: 0; 
  transform-origin: center bottom;
}




/* 去除阴影 */
.mes_button,
.mes_edit_buttons,
#completion_prompt_manager
  #completion_prompt_manager_list
  li.completion_prompt_manager_prompt
  span
  span
  span {
  filter: none !important;
}

input:disabled, 
select:disabled, 
textarea:disabled {
  background: rgba(237, 229, 216, 0.6) !important;
  color: #9E7C6E !important;
  border-style: dashed !important;
}

.drawer-icon::before,
#leftNavDrawerIcon::before,
#rightNavDrawerIcon::before {
    content: '';
    display: block;
    width: 40px;
    height: 40px;
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    margin-right: px;
    margin-left: -8px;
}
.drawer-icon {
    display: flex;
    align-items: center;
    justify-content: flex-start;
    padding-left: 12px;
}

/* 调整图标容器样式 */
.drawer-icon {
    display: flex;
    align-items: center;
    justify-content: flex-start;
    padding-left: 1px;
}

/* 强制非悬停 */
.drawer-icon,
.fa-bars,
#extensionsMenuButton,
.fa-paper-plane {
  opacity: 1 !important;
  transition: opacity 0.2s ease !important;
}

/* 左侧导航图标 */
#leftNavDrawerIcon::before {
    background-image: url('https://files.catbox.moe/po8un9.png');
}

/* 系统设置图标 */
#sys-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/pjvcz2.png');
}

/* 高级格式图标 */
#advanced-formatting-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/po8un9.png');
}

/* 世界信息图标 */
#WI-SP-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/pjvcz2.png');
}

/* 用户设置图标 */
#user-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/po8un9.png');
}

/* Logo图标 */
#logo_block .drawer-icon::before {
    background-image: url('https://files.catbox.moe/pjvcz2.png');
}

/* 扩展设置图标 */
#extensions-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/po8un9.png');
}

/* 记忆表格 */
#table_drawer_icon::before {
    background-image: url('https://files.catbox.moe/pjvcz2.png');
}

/* 角色管理图标 */
#persona-management-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/po8un9.png');
}

/* 右侧导航图标 */
#rightNavDrawerIcon::before {
    background-image: url('https://files.catbox.moe/pjvcz2.png');
}

/* 特殊按钮样式 */
/* 菜单按钮 */
.fa-bars {
  background: url('https://files.catbox.moe/nzpntq.png') center/contain no-repeat !important;
  width: 34px !important;
  height: 35px !important;

}

/* 扩展按钮 */
#extensionsMenuButton {
  background: url('https://files.catbox.moe/7ud6te.png') center/contain no-repeat !important;
  width: 35px !important;
  height: 35px !important;
  margin-top: 1px !important;
}

